 * Apply per-item modifiers (cursed, high enchantment) to a base premium.
 */
export function applyItemModifiers(basePremium: number, item: Item): number {
  let premium = basePremium;
  if (item.cursed) {
    premium *= 1.5;
  }
  if ((item.enchantment ?? 0) >= 5) {
    premium *= 1.3;
  }
  return premium;
}

